          </button>
        </form>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { View, Text, StyleSheet, ScrollView, TouchableOpacity, Alert, Switch, StatusBar } from 'react-native';
import { User, Package, MapPin, CreditCard, LogOut, ChevronRight } from 'lucide-react-native';
import { useNavigation } from '@react-navigation/native';
import { logout } from '../../services/auth';
import { getToken, setToken } from '../../services/storage';

export default function Perfil() {
  const navigation = useNavigation();
  const [notificationsEnabled, setNotificationsEnabled] = useState(true);

  const menuItems = [
    {
      icon: Package,
      label: 'Mis Pedidos',
      subtitle: 'Ver historial de compras',
      onClick: () => Alert.alert('Aviso', 'Función en desarrollo'),
    },
    {
      icon: MapPin,
      label: 'Direcciones',
      subtitle: 'Gestionar direcciones de envío',
      onClick: () => Alert.alert('Aviso', 'Función en desarrollo'),
    },
    {
      icon: CreditCard,
      label: 'Métodos de Pago',
      subtitle: 'Gestionar tarjetas guardadas',
      onClick: () => Alert.alert('Aviso', 'Función en desarrollo'),
    },
  ];

  const handleLogout = () => {
    Alert.alert(
      "Cerrar Sesión",
      "¿Estás seguro de que deseas cerrar sesión?",
      [
        { text: "Cancelar", style: "cancel" },
        { 
          text: "Salir", 
          style: "destructive", 
          onPress: async () => {
            try {
              const token = getToken();
              if (token) {
                await logout(token);
              }
            } catch (error) {
              console.error("Error al cerrar sesión:", error);
            } finally {
              setToken(null);
              navigation.reset({
                index: 0,
                routes: [{ name: 'InicioSesion' as never }],
              });
            }
          }
        }
      ]
    );
  };

  return (
    <ScrollView style={styles.container} showsVerticalScrollIndicator={false}>
      <StatusBar barStyle="dark-content" />

      <View style={styles.header}>
        <View style={styles.avatarContainer}>
          <User size={40} color="#FFF" />
        </View>
        <View>
          <Text style={styles.userName}>Usuario Comprador</Text>
          <Text style={styles.userEmail}>comprador@prueba.com</Text>
        </View>
      </View>

      <View style={styles.content}>
        <View style={styles.sectionCard}>
          <View style={styles.sectionHeader}>
            <Text style={styles.sectionTitle}>Mi Cuenta</Text>
          </View>
          <View style={styles.menuList}>
            {menuItems.map((item, index) => (
              <TouchableOpacity 
                key={index} 
                style={[styles.menuItem, index === menuItems.length - 1 && { borderBottomWidth: 0 }]}
                onPress={item.onClick}
              >
                <View style={styles.iconCircle}>
                  <item.icon size={20} color="#1C273F" />
                </View>
                <View style={{ flex: 1 }}>
                  <Text style={styles.menuLabel}>{item.label}</Text>
                  <Text style={styles.menuSubtitle}>{item.subtitle}</Text>
                </View>
                <ChevronRight size={20} color="#9CA3AF" />
              </TouchableOpacity>
            ))}
          </View>
        </View>

